"use client";
import { useState } from 'react';
import { searchYouTube } from '@/lib/youtube';
import SongCard from '@/components/SongCard';
import { Search } from 'lucide-react';

export default function SearchPage() {
  const [query, setQuery] = useState("");
  const [results, setResults] = useState([]);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    const songs = await searchYouTube(query);
    setResults(songs);
  };

  return (
    <div>
      <form onSubmit={handleSearch} className="relative mb-8">
        <Search className="absolute left-3 top-2.5 text-zinc-400" size={20} />
        <input 
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="What do you want to listen to?" 
          className="w-full max-w-md bg-[#242424] rounded-full py-2 px-10 focus:outline-none border-2 border-transparent focus:border-white"
        />
      </form>

      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-4">
        {results.map((song: any) => (
          <SongCard key={song.id} {...song} />
        ))}
      </div>
    </div>
  );
}