import { create } from 'zustand';

interface PlayerState {
  currentTrackId: string | null;
  trackDetails: { title: string; thumbnail: string } | null;
  isPlaying: boolean;
  volume: number;
  currentTime: number;
  duration: number;
  setTrack: (id: string, details: { title: string; thumbnail: string }) => void;
  togglePlay: () => void;
  setVolume: (val: number) => void;
  setProgress: (time: number) => void;
  setDuration: (duration: number) => void;
  resetProgress: () => void;
}

export const usePlayerStore = create<PlayerState>((set) => ({
  currentTrackId: null,
  trackDetails: null,
  isPlaying: false,
  volume: 0.5,
  currentTime: 0,
  duration: 0,
  setTrack: (id, details) => set({ 
    currentTrackId: id, 
    trackDetails: details, 
    isPlaying: true, // Force play on new track
    currentTime: 0,
    duration: 0 // Reset duration when changing tracks
  }),
  togglePlay: () => set((state) => ({ isPlaying: state.currentTrackId ? !state.isPlaying : false })),
  setVolume: (val) => set({ volume: val }),
  setProgress: (time) => set({ currentTime: time }),
  setDuration: (duration) => set({ duration: duration }),
  resetProgress: () => set({ currentTime: 0, duration: 0 })
}));